     1→const http = require('http');
     2→const fs = require('fs');
     3→const path = require('path');
     4→
     5→const PORT = process.env.PORT || 5000;
     6→
     7→const mimeTypes = {
     8→  '.html': 'text/html',
     9→  '.css':  'text/css',
    10→  '.js':   'text/javascript',
    11→  '.png':  'image/png',
    12→  '.jpg':  'image/jpeg',
    13→  '.jpeg': 'image/jpeg',
    14→  '.svg':  'image/svg+xml',
    15→  '.ico':  'image/x-icon',
    16→};
    17→
    18→const server = http.createServer((req, res) => {
    19→  let urlPath = req.url.split('?')[0];
    20→
    21→  // Redirect root to first onboarding screen (proper redirect keeps URL correct)
    22→  if (urlPath === '/' || urlPath === '') {
    23→    res.writeHead(302, { Location: '/html/onboarding-1.html' });
    24→    res.end();
    25→    return;
    26→  }
    27→
    28→  // If someone requests /onboarding-*.html directly, redirect to /html/onboarding-*.html
    29→  if (/^\/onboarding-\d+\.html$/.test(urlPath)) {
    30→    res.writeHead(302, { Location: '/html' + urlPath });
    31→    res.end();
    32→    return;
    33→  }
    34→
    35→  // If someone requests /register.html directly, redirect to /html/register.html
    36→  if (/^\/[a-z-]+\.html$/.test(urlPath)) {
    37→    res.writeHead(302, { Location: '/html' + urlPath });
    38→    res.end();
    39→    return;
    40→  }
    41→
    42→  const filePath = path.join(__dirname, urlPath);
    43→
    44→  fs.readFile(filePath, (err, data) => {
    45→    if (err) {
    46→      res.writeHead(404, { 'Content-Type': 'text/plain' });
    47→      res.end('404 Not Found: ' + urlPath);
    48→      return;
    49→    }
    50→
    51→    const ext = path.extname(filePath).toLowerCase();
    52→    const contentType = mimeTypes[ext] || 'application/octet-stream';
    53→
    54→    res.writeHead(200, { 'Content-Type': contentType });
    55→    res.end(data);
    56→  });
    57→});
    58→
    59→server.listen(PORT, '0.0.0.0', () => {
    60→  console.log(`StressCare server running on port ${PORT}`);
    61→});
