/* ── Export Modal ────────────────────────────────────── */
.rd-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(15,25,50,0.45);
  display: flex;
  align-items: flex-end;
  justify-content: center;
  z-index: 999;
  backdrop-filter: blur(2px);
}

.rd-modal {
  background: #fff;
  border-radius: 28px 28px 0 0;
  padding: 28px 20px 36px;
  width: 100%;
  max-width: 390px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  animation: slideUp 0.3s cubic-bezier(0.34,1.56,0.64,1);
}

@keyframes slideUp {
  from { transform: translateY(100%); opacity: 0; }
  to   { transform: translateY(0);    opacity: 1; }
}

.rd-modal-icon {
  width: 56px; height: 56px;
  border-radius: 18px;
  background: linear-gradient(135deg, #2563eb, #3b82f6);
  display: flex; align-items: center; justify-content: center;
  font-size: 24px;
  color: #fff;
  margin-bottom: 4px;
  box-shadow: 0 6px 18px rgba(37,99,235,0.30);
}

.rd-modal-title {
  font-size: 18px;
  font-weight: 800;
  color: #1a2b4b;
}

.rd-modal-sub {
  font-size: 12px;
  color: #9aadc9;
  margin-bottom: 8px;
}

.rd-modal-options {
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-bottom: 8px;
}

.rd-modal-opt {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 14px;
  background: #f5f8ff;
  border: 1.5px solid #e0eaff;
  border-radius: 16px;
  padding: 14px 16px;
  cursor: pointer;
  text-align: left;
  transition: all 0.18s;
}

.rd-modal-opt:hover {
  background: #dbeafe;
  border-color: #2563eb;
  transform: translateY(-1px);
}

.rd-modal-opt > i {
  font-size: 20px;
  color: #2563eb;
  flex-shrink: 0;
  width: 24px;
  text-align: center;
}

.rd-modal-opt-title {
  font-size: 13px;
  font-weight: 700;
  color: #1a2b4b;
}

.rd-modal-opt-sub {
  font-size: 11px;
  color: #9aadc9;
  margin-top: 2px;
}

.rd-modal-cancel {
  width: 100%;
  background: transparent;
  border: 1.5px solid #e0eaff;
  border-radius: 14px;
  padding: 13px;
  font-size: 14px;
  font-weight: 600;
  color: #7a8cad;
  cursor: pointer;
  transition: all 0.18s;
  margin-top: 2px;
}

.rd-modal-cancel:hover { background: #f5f8ff; }

/* ── Toast ───────────────────────────────────────────── */
.rd-toast {
  position: fixed;
  bottom: 90px;
  left: 50%;
  transform: translateX(-50%) translateY(20px);
  background: #1a2b4b;
  color: #fff;
  padding: 10px 20px;
  border-radius: 30px;
  font-size: 13px;
  font-weight: 600;
  opacity: 0;
  transition: all 0.3s;
  z-index: 1000;
  white-space: nowrap;
  box-shadow: 0 4px 16px rgba(0,0,0,0.18);
}

.rd-toast-show {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

/* ── Print / PDF Export ──────────────────────────────── */
@media print {
  body { background: #fff !important; }
  .phone-frame {
    box-shadow: none !important;
    border-radius: 0 !important;
    max-width: 100% !important;
    height: auto !important;
    margin: 0 !important;
  }
  .rd-screen { height: auto !important; overflow: visible !important; }
  .rd-scroll  { overflow: visible !important; height: auto !important; }
  .dp-status-bar, .dp-topnav, .dp-bottom-nav,
  .rd-tabs, .rd-export-btn, .rd-modal-overlay { display: none !important; }
  .rd-tab-panel { display: block !important; }
  #tab-vitals, #tab-sleep, #tab-risk { margin-top: 16px; }
  .rd-page-header { margin-top: 0; }
  .rd-card { break-inside: avoid; box-shadow: none !important; border: 1px solid #e0eaff; }
}

/* ── Bottom Nav ─────────────────────────────────────── */

