/* ── Title Row ───────────────────────────────────────── */
.hist-title-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin: 4px 0 10px;
}

.hist-title { margin: 0; }

.hist-filter-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  background: #fff;
  border: 1.5px solid #d0dff0;
  border-radius: 22px;
  padding: 7px 14px;
  font-size: 12px;
  font-weight: 600;
  color: #2563eb;
  cursor: pointer;
  box-shadow: 0 2px 8px rgba(37,99,235,0.09);
  transition: all 0.2s;
  max-width: 160px;
  overflow: hidden;
  white-space: nowrap;
  text-overflow: ellipsis;
}

.hist-filter-btn:hover { background: #eff6ff; }
.hist-filter-btn i { font-size: 13px; flex-shrink: 0; }

/* ── Filter Chip ─────────────────────────────────────── */
.hist-filter-chip {
  display: flex;
  align-items: center;
  gap: 7px;
  background: #dbeafe;
  border: 1.5px solid #93c5fd;
  border-radius: 22px;
  padding: 6px 12px;
  font-size: 12px;
  font-weight: 600;
  color: #1d4ed8;
  margin-bottom: 10px;
  width: fit-content;
}

.hist-filter-chip i { font-size: 12px; }

.hist-chip-clear {
  background: none;
  border: none;
  color: #60a5fa;
  font-size: 13px;
  cursor: pointer;
  padding: 0 0 0 4px;
  line-height: 1;
  display: flex; align-items: center;
}

/* ── No Session Empty State ──────────────────────────── */
.hist-no-session {
  flex-direction: column;
  align-items: center;
  gap: 8px;
  padding: 28px 14px;
  color: #9aadc9;
  font-size: 13px;
  font-weight: 500;
}

.hist-no-session i { font-size: 30px; color: #c5d3e8; }

/* ── Calendar Modal ──────────────────────────────────── */
.hist-cal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(15,25,50,0.45);
  display: flex;
  align-items: flex-end;
  justify-content: center;
  z-index: 998;
  backdrop-filter: blur(2px);
}

.hist-cal-modal {
  background: #fff;
  border-radius: 28px 28px 0 0;
  padding: 24px 20px 36px;
  width: 100%;
  max-width: 390px;
  animation: calSlideUp 0.32s cubic-bezier(0.34,1.4,0.64,1);
}

@keyframes calSlideUp {
  from { transform: translateY(100%); opacity: 0; }
  to   { transform: translateY(0);    opacity: 1; }
}

/* Header row */
.hist-cal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
}

.hist-cal-month-label {
  font-size: 16px;
  font-weight: 800;
  color: #1a2b4b;
}

.hist-cal-nav {
  width: 34px; height: 34px;
  border-radius: 50%;
  border: 1.5px solid #d0dff0;
  background: #f5f8ff;
  color: #2563eb;
  font-size: 13px;
  cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  transition: all 0.18s;
}

.hist-cal-nav:hover { background: #dbeafe; border-color: #93c5fd; }

/* Weekday header */
.hist-cal-weekdays {
  display: grid;
  grid-template-columns: repeat(7, 1fr);
  text-align: center;
  margin-bottom: 6px;
}

.hist-cal-weekdays span {
  font-size: 11px;
  font-weight: 700;
  color: #9aadc9;
  padding: 4px 0;
}

/* Grid */
.hist-cal-grid {
  display: grid;
  grid-template-columns: repeat(7, 1fr);
  gap: 3px;
  margin-bottom: 14px;
}

.hist-cal-cell {
  aspect-ratio: 1;
  border: none;
  background: transparent;
  border-radius: 50%;
  font-size: 13px;
  font-weight: 500;
  color: #1a2b4b;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  transition: all 0.15s;
}

.hist-cal-cell:hover:not(:disabled):not(.hist-cal-selected) {
  background: #eff6ff;
  color: #2563eb;
}

.hist-cal-blank { pointer-events: none; }

.hist-cal-today {
  font-weight: 800;
  color: #2563eb;
}

.hist-cal-today::after {
  content: '';
  position: absolute;
  bottom: 3px;
  width: 4px; height: 4px;
  border-radius: 50%;
  background: #2563eb;
}

.hist-cal-has-session::before {
  content: '';
  position: absolute;
  top: 4px;
  right: 4px;
  width: 5px; height: 5px;
  border-radius: 50%;
  background: #22c55e;
  z-index: 1;
}

.hist-cal-selected {
  background: #2563eb !important;
  color: #fff !important;
  font-weight: 700;
  box-shadow: 0 3px 10px rgba(37,99,235,0.35);
}

.hist-cal-selected::before { background: #fff !important; }
.hist-cal-selected::after  { background: #fff !important; }

.hist-cal-future {
  color: #c5d3e8 !important;
  cursor: not-allowed;
}

/* Legend */
.hist-cal-legend {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;
  color: #9aadc9;
  margin-bottom: 16px;
}

.hist-cal-dot-green {
  width: 8px; height: 8px;
  border-radius: 50%;
  background: #22c55e;
  flex-shrink: 0;
}

/* Actions */
.hist-cal-actions {
  display: flex;
  gap: 10px;
}

.hist-cal-cancel {
  flex: 1;
  background: #f5f8ff;
  border: 1.5px solid #e0eaff;
  border-radius: 14px;
  padding: 13px;
  font-size: 14px;
  font-weight: 600;
  color: #7a8cad;
  cursor: pointer;
  transition: all 0.18s;
}

.hist-cal-cancel:hover { background: #e8f0ff; }

.hist-cal-apply {
  flex: 1;
  background: #2563eb;
  border: none;
  border-radius: 14px;
  padding: 13px;
  font-size: 14px;
  font-weight: 700;
  color: #fff;
  cursor: pointer;
  box-shadow: 0 4px 14px rgba(37,99,235,0.30);
  transition: all 0.18s;
}

.hist-cal-apply:hover:not(:disabled) { background: #1d4ed8; }

.hist-cal-apply:disabled {
  background: #c5d3e8;
  box-shadow: none;
  cursor: not-allowed;
}

/* ── View Full Report Button ─────────────────────────── */

