arguments.content:
/* ── Notifications Screen ──────────────────────────────── */

.notif-screen {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, #deeeff 0%, #f0f6ff 18%, #f5f8ff 100%);
  overflow: hidden;
}

/* ── Back btn in top nav ─────────────────────────────── */
.notif-back-btn {
  width: 34px; height: 34px;
  border-radius: 50%;
  border: 1.5px solid #d0dff0;
  background: #fff;
  color: #1a2b4b;
  font-size: 13px;
  display: flex; align-items: center; justify-content: center;
  text-decoration: none;
  flex-shrink: 0;
  box-shadow: 0 1px 6px rgba(37,99,235,0.07);
}

/* ── Top nav center ──────────────────────────────────── */
.notif-topnav-center {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;
  padding-left: 10px;
}

.notif-page-title {
  font-size: 18px;
  font-weight: 800;
  color: #1a2b4b;
}

.notif-badge-count {
  background: #ef4444;
  color: #fff;
  font-size: 10px;
  font-weight: 700;
  border-radius: 20px;
  padding: 2px 8px;
  display: inline-flex;
  align-items: center;
}

.notif-read-all-btn {
  background: none;
  border: 1.5px solid #d0dff0;
  border-radius: 20px;
  padding: 5px 11px;
  font-size: 11px;
  font-weight: 600;
  color: #2563eb;
  cursor: pointer;
  white-space: nowrap;
  transition: all 0.18s;
  flex-shrink: 0;
}

.notif-read-all-btn:hover { background: #eff6ff; }

/* ── Filter Tabs ─────────────────────────────────────── */
.notif-filter-tabs {
  display: flex;
  gap: 0;
  background: #fff;
  border-radius: 14px;
  padding: 4px;
  margin: 0 14px 10px;
  box-shadow: 0 2px 8px rgba(37,99,235,0.07);
  flex-shrink: 0;
}

.notif-ftab {
  flex: 1;
  border: none;
  background: transparent;
  color: #7a8cad;
  font-size: 11px;
  font-weight: 600;
  padding: 7px 4px;
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.2s;
}

.notif-ftab-active {
  background: #2563eb;
  color: #fff;
  box-shadow: 0 2px 8px rgba(37,99,235,0.28);
}

/* ── Scroll ──────────────────────────────────────────── */
.notif-scroll {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  scrollbar-width: none;
  -ms-overflow-style: none;
  padding: 0 14px;
}
.notif-scroll::-webkit-scrollbar { display: none; }

/* ── Section Label ───────────────────────────────────── */
.notif-section-label {
  font-size: 12px;
  font-weight: 700;
  color: #9aadc9;
  text-transform: uppercase;
  letter-spacing: 0.6px;
  margin: 10px 0 8px 2px;
}

/* ── Notification Card ───────────────────────────────── */
.notif-card {
  position: relative;
  background: #fff;
  border-radius: 18px;
  padding: 14px 12px;
  margin-bottom: 10px;
  display: flex;
  align-items: flex-start;
  gap: 12px;
  box-shadow: 0 2px 12px rgba(37,99,235,0.07);
  transition: transform 0.18s, box-shadow 0.18s, opacity 0.18s;
  overflow: hidden;
}

.notif-card:active { transform: scale(0.98); }

/* Unread state */
.notif-card.notif-unread {
  background: #fff;
  border-left: 3.5px solid #2563eb;
}

.notif-unread-dot {
  position: absolute;
  top: 14px;
  right: 40px;
  width: 8px; height: 8px;
  border-radius: 50%;
  background: #2563eb;
  flex-shrink: 0;
}

/* ── Icon Wrap ───────────────────────────────────────── */
.notif-icon-wrap {
  width: 40px; height: 40px;
  border-radius: 13px;
  display: flex; align-items: center; justify-content: center;
  font-size: 17px;
  flex-shrink: 0;
}

.notif-icon-red    { background: #fee2e2; color: #ef4444; }
.notif-icon-amber  { background: #fef3c7; color: #d97706; }
.notif-icon-blue   { background: #dbeafe; color: #2563eb; }
.notif-icon-purple { background: #ede9fe; color: #7c3aed; }
.notif-icon-teal   { background: #d1fae5; color: #059669; }
.notif-icon-green  { background: #dcfce7; color: #16a34a; }
.notif-icon-indigo { background: #e0e7ff; color: #4f46e5; }

/* ── Body ────────────────────────────────────────────── */
.notif-body {
  flex: 1;
  min-width: 0;
}

.notif-title {
  font-size: 13px;
  font-weight: 700;
  color: #1a2b4b;
  margin-bottom: 3px;
  line-height: 1.2;
}

.notif-desc {
  font-size: 11.5px;
  color: #7a8cad;
  line-height: 1.5;
  margin-bottom: 6px;
}

.notif-meta {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

.notif-time {
  font-size: 10.5px;
  color: #b0bcd4;
  display: flex;
  align-items: center;
  gap: 4px;
}

.notif-time i { font-size: 10px; }

.notif-action-link {
  font-size: 11px;
  font-weight: 700;
  color: #2563eb;
  text-decoration: none;
  transition: color 0.15s;
}

.notif-action-link:hover { color: #1d4ed8; }

/* ── Dismiss btn ─────────────────────────────────────── */
.notif-dismiss {
  background: none;
  border: none;
  color: #c5d3e8;
  font-size: 14px;
  cursor: pointer;
  padding: 2px 0 0 4px;
  flex-shrink: 0;
  line-height: 1;
  transition: color 0.15s;
}

.notif-dismiss:hover { color: #7a8cad; }

/* ── Fade out animation ──────────────────────────────── */
@keyframes notifFadeOut {
  from { opacity: 1; transform: translateX(0) scaleY(1); max-height: 200px; }
  to   { opacity: 0; transform: translateX(40px) scaleY(0.8); max-height: 0; margin: 0; padding: 0; }
}

/* ── Empty State ─────────────────────────────────────── */
.notif-empty {
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 12px;
  padding: 60px 20px;
  text-align: center;
}

.notif-empty-icon {
  width: 72px; height: 72px;
  border-radius: 50%;
  background: #f0f4fa;
  display: flex; align-items: center; justify-content: center;
  font-size: 30px;
  color: #c5d3e8;
}

.notif-empty-title {
  font-size: 17px;
  font-weight: 800;
  color: #1a2b4b;
}

.notif-empty-sub {
  font-size: 13px;
  color: #9aadc9;
}

/* ── Bottom Nav (shared) ─────────────────────────────── */
.dp-bottom-nav {
  display: flex;
  justify-content: space-around;
  align-items: center;
  background: #fff;
  border-top: 1px solid #e8f0fb;
  padding: 8px 0 10px;
  flex-shrink: 0;
}

.dp-bottom-nav .nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  text-decoration: none;
  color: #9aadc9;
  font-size: 10px;
  font-weight: 500;
  transition: color 0.2s;
}

.dp-bottom-nav .nav-item i { font-size: 18px; }
.dp-bottom-nav .nav-item.nav-active { color: #2563eb; }

/* ── Migraine Risk Screen ──────────────────────────────── */

.mg-screen {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, #deeeff 0%, #f0f6ff 18%, #f5f8ff 100%);
  overflow: hidden;
}

/* ── Scroll ──────────────────────────────────────────── */
.mg-scroll {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  scrollbar-width: none;
  -ms-overflow-style: none;
  padding: 0 14px;
}
.mg-scroll::-webkit-scrollbar { display: none; }

/* ── Page Header ─────────────────────────────────────── */
.mg-page-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin: 4px 0 14px;
}

.mg-header-left {
  display: flex;
  align-items: center;
  gap: 12px;
}

.mg-back-btn {
  width: 34px; height: 34px;
  border-radius: 50%;
  border: 1.5px solid #d0dff0;
  background: #fff;
  color: #1a2b4b;
  font-size: 13px;
  display: flex; align-items: center; justify-content: center;
  text-decoration: none;
  flex-shrink: 0;
  box-shadow: 0 1px 6px rgba(37,99,235,0.07);
}

.mg-title {
  font-size: 22px;
  font-weight: 800;
  color: #1a2b4b;
  margin: 0;
  line-height: 1.1;
}

.mg-date {
  font-size: 11px;
  color: #9aadc9;
  margin-top: 2px;
}

.mg-cal-btn {
  width: 36px; height: 36px;
  border-radius: 10px;
  border: 1.5px solid #d0dff0;
  background: #fff;
  color: #1a2b4b;
  font-size: 14px;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer;
  box-shadow: 0 1px 6px rgba(37,99,235,0.07);
}

/* ── Card Base ───────────────────────────────────────── */
.mg-card {
  background: #fff;
  border-radius: 20px;
  padding: 16px;
  margin-bottom: 12px;
  box-shadow: 0 2px 12px rgba(37,99,235,0.07);
}

.mg-card-title {
  font-size: 14px;
  font-weight: 800;
  color: #1a2b4b;
}

.mg-card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 10px;
}

/* ── Risk Summary Card ───────────────────────────────── */
.mg-risk-summary-card {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 18px 18px 14px;
}

/* Gauge */
.mg-gauge-wrap {
  position: relative;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
}

.mg-gauge-label {
  text-align: center;
  margin-top: 2px;
}

.mg-gauge-level {
  font-size: 14px;
  font-weight: 800;
  color: #22c55e;
  line-height: 1;
}

.mg-gauge-pct {
  font-size: 28px;
  font-weight: 900;
  color: #1a2b4b;
  line-height: 1.1;
}

.mg-gauge-sign {
  font-size: 16px;
  font-weight: 700;
}

.mg-gauge-sub {
  font-size: 10px;
  color: #9aadc9;
  font-weight: 500;
  margin-top: 1px;
}

/* Right info */
.mg-risk-info {
  flex: 1;
  padding-left: 6px;
  border-left: 1.5px solid #f0f4fa;
}

.mg-risk-info-lbl {
  font-size: 10.5px;
  color: #9aadc9;
  font-weight: 500;
  margin-bottom: 3px;
}

.mg-risk-level-row {
  display: flex;
  align-items: center;
  gap: 7px;
}

.mg-risk-level-val {
  font-size: 17px;
  font-weight: 800;
  color: #22c55e;
}

.mg-risk-green-dot {
  width: 9px; height: 9px;
  border-radius: 50%;
  background: #22c55e;
  box-shadow: 0 0 0 3px rgba(34,197,94,0.20);
  flex-shrink: 0;
}

.mg-risk-stable {
  font-size: 15px;
  font-weight: 700;
  color: #22c55e;
  margin-top: 2px;
}

/* ── Risk Factors Grid ───────────────────────────────── */
.mg-factors-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  margin-top: 12px;
}

.mg-factor-cell {
  display: flex;
  align-items: center;
  gap: 10px;
  background: #f8faff;
  border-radius: 13px;
  padding: 10px 11px;
}

.mg-factor-icon {
  width: 34px; height: 34px;
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 15px;
  flex-shrink: 0;
}

.mg-fi-purple { background: #ede9fe; color: #7c3aed; }
.mg-fi-red    { background: #fee2e2; color: #ef4444; }
.mg-fi-blue   { background: #dbeafe; color: #2563eb; }
.mg-fi-orange { background: #ffedd5; color: #f97316; }
.mg-fi-cyan   { background: #cffafe; color: #0891b2; }
.mg-fi-green  { background: #dcfce7; color: #16a34a; }

.mg-factor-info { flex: 1; min-width: 0; }

.mg-factor-lbl {
  font-size: 10px;
  color: #9aadc9;
  font-weight: 500;
  line-height: 1.2;
}

.mg-factor-val {
  font-size: 13px;
  font-weight: 700;
  line-height: 1.2;
  margin-top: 1px;
}

.mg-val-green { color: #22c55e; }
.mg-val-amber { color: #d97706; }
.mg-val-red   { color: #ef4444; }

/* ── Weekly Badge ────────────────────────────────────── */
.mg-weekly-badge {
  font-size: 11px;
  font-weight: 700;
  color: #2563eb;
  background: #eff6ff;
  border-radius: 20px;
  padding: 3px 10px;
}

/* ── Recent Signals ──────────────────────────────────── */
.mg-signals-row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.mg-signal-cell {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 7px;
  text-align: center;
}

.mg-signal-icon {
  width: 44px; height: 44px;
  border-radius: 14px;
  display: flex; align-items: center; justify-content: center;
  font-size: 18px;
}

.mg-si-green  { background: #dcfce7; color: #16a34a; }
.mg-si-amber  { background: #fef3c7; color: #d97706; }
.mg-si-purple { background: #ede9fe; color: #7c3aed; }
.mg-si-blue   { background: #dbeafe; color: #2563eb; }

.mg-signal-lbl {
  font-size: 9.5px;
  color: #5a6882;
  font-weight: 500;
  line-height: 1.3;
  max-width: 62px;
}

/* ── Recommendations ─────────────────────────────────── */
.mg-rec-list {
  display: flex;
  flex-direction: column;
}

.mg-rec-row {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 0;
  border-bottom: 1px solid #f0f4fa;
  cursor: pointer;
  transition: background 0.15s;
}

.mg-rec-icon-wrap {
  width: 34px; height: 34px;
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 14px;
  flex-shrink: 0;
}

.mg-ri-blue   { background: #dbeafe; color: #2563eb; }
.mg-ri-green  { background: #dcfce7; color: #16a34a; }
.mg-ri-purple { background: #ede9fe; color: #7c3aed; }
.mg-ri-indigo { background: #e0e7ff; color: #4f46e5; }

.mg-rec-text {
  flex: 1;
  font-size: 13px;
  font-weight: 600;
  color: #1a2b4b;
}

.mg-rec-arrow {
  color: #c5d3e8;
  font-size: 11px;
  flex-shrink: 0;
}

/* ── Set Risk Alerts Button ──────────────────────────── */
.mg-alert-btn {
  width: 100%;
  background: #2563eb;
  color: #fff;
  border: none;
  border-radius: 16px;
  padding: 16px;
  font-size: 15px;
  font-weight: 700;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  box-shadow: 0 4px 16px rgba(37,99,235,0.28);
  transition: all 0.2s;
  margin-bottom: 4px;
}

.mg-alert-btn:hover {
  background: #1d4ed8;
  transform: translateY(-1px);
}

/* ── Toast ───────────────────────────────────────────── */
.mg-toast {
  position: fixed;
  bottom: 90px;
  left: 50%;
  transform: translateX(-50%) translateY(20px);
  background: #1a2b4b;
  color: #fff;
  padding: 10px 22px;
  border-radius: 30px;
  font-size: 13px;
  font-weight: 600;
  opacity: 0;
  transition: all 0.3s;
  z-index: 1000;
  white-space: nowrap;
  box-shadow: 0 4px 16px rgba(0,0,0,0.18);
  display: flex;
  align-items: center;
  gap: 8px;
}

.mg-toast-show {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

/* ── Bottom Nav (shared) ─────────────────────────────── */
.dp-bottom-nav {
  display: flex;
  justify-content: space-around;
  align-items: center;
  background: #fff;
  border-top: 1px solid #e8f0fb;
  padding: 8px 0 10px;
  flex-shrink: 0;
}

.dp-bottom-nav .nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  text-decoration: none;
  color: #9aadc9;
  font-size: 10px;
  font-weight: 500;
  transition: color 0.2s;
}

.dp-bottom-nav .nav-item i { font-size: 18px; }
.dp-bottom-nav .nav-item.nav-active { color: #2563eb; }

