arguments.content:
/* ── Notifications Screen ──────────────────────────────── */

.notif-screen {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, #deeeff 0%, #f0f6ff 14%, #f5f8ff 100%);
  overflow: hidden;
}

/* ── Page Header ─────────────────────────────────────── */
.notif-page-header {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 2px 16px 14px;
  flex-shrink: 0;
}

.notif-back-btn {
  width: 34px; height: 34px;
  border-radius: 50%;
  border: 1.5px solid #d0dff0;
  background: #fff;
  color: #1a2b4b;
  font-size: 13px;
  display: flex; align-items: center; justify-content: center;
  text-decoration: none;
  flex-shrink: 0;
  box-shadow: 0 1px 6px rgba(37,99,235,0.07);
}

.notif-page-title {
  font-size: 22px;
  font-weight: 800;
  color: #1a2b4b;
  margin: 0;
}

/* ── Filter Tabs ─────────────────────────────────────── */
.notif-filter-tabs {
  display: flex;
  gap: 8px;
  padding: 0 16px 12px;
  flex-shrink: 0;
}

.notif-ftab {
  border: 1.5px solid #e2eaf5;
  background: #fff;
  color: #5a6882;
  font-size: 12px;
  font-weight: 600;
  padding: 7px 16px;
  border-radius: 30px;
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
}

.notif-ftab-active {
  background: #2563eb;
  color: #fff;
  border-color: #2563eb;
  box-shadow: 0 3px 10px rgba(37,99,235,0.25);
}

/* ── Scroll ──────────────────────────────────────────── */
.notif-scroll {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  scrollbar-width: none;
  -ms-overflow-style: none;
  background: #fff;
  border-radius: 20px 20px 0 0;
  padding: 6px 0 0;
}
.notif-scroll::-webkit-scrollbar { display: none; }

/* ── Section Label ───────────────────────────────────── */
.notif-section-label {
  font-size: 14px;
  font-weight: 800;
  color: #1a2b4b;
  padding: 14px 18px 8px;
}

/* ── Notification Row ────────────────────────────────── */
.notif-row {
  display: flex;
  align-items: flex-start;
  gap: 14px;
  padding: 14px 18px;
  border-bottom: 1px solid #f3f6fb;
  cursor: pointer;
  transition: background 0.15s;
  text-decoration: none;
}

.notif-row:last-of-type { border-bottom: none; }
.notif-row:active { background: #f8faff; }

/* ── Icon Wrap ───────────────────────────────────────── */
.notif-icon-wrap {
  width: 46px; height: 46px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 18px;
  flex-shrink: 0;
  margin-top: 1px;
}

.notif-icon-red    { background: #fee2e2; color: #ef4444; }
.notif-icon-amber  { background: #fef3c7; color: #d97706; }
.notif-icon-blue   { background: #dbeafe; color: #2563eb; }
.notif-icon-purple { background: #ede9fe; color: #7c3aed; }
.notif-icon-teal   { background: #d1fae5; color: #059669; }
.notif-icon-green  { background: #dcfce7; color: #16a34a; }
.notif-icon-indigo { background: #e0e7ff; color: #4f46e5; }

/* ── Body ────────────────────────────────────────────── */
.notif-body {
  flex: 1;
  min-width: 0;
}

.notif-title {
  font-size: 13.5px;
  font-weight: 700;
  color: #1a2b4b;
  margin-bottom: 4px;
