.dp-bottom-nav .nav-item.nav-active { color: #2563eb; }

/* ── Profile Screen ──────────────────────────────────── */

.pf-screen {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, #deeeff 0%, #f0f6ff 14%, #f5f8ff 100%);
  overflow: hidden;
}

/* ── Scroll ──────────────────────────────────────────── */
.pf-scroll {
