/* ── Detail Bottom Sheet ─────────────────────────────── */
.nd-overlay {
  position: absolute;
  inset: 0;
  background: rgba(15, 25, 50, 0.45);
  z-index: 100;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.3s ease;
  border-radius: inherit;
}

.nd-overlay.nd-show {
  opacity: 1;
  pointer-events: all;
}

.nd-sheet {
  position: absolute;
  bottom: 0; left: 0; right: 0;
  background: #fff;
  border-radius: 26px 26px 0 0;
  z-index: 101;
  padding: 10px 20px 28px;
  transform: translateY(100%);
  transition: transform 0.35s cubic-bezier(0.32, 0.72, 0, 1);
  box-shadow: 0 -8px 40px rgba(37,99,235,0.14);
}

.nd-sheet.nd-open {
  transform: translateY(0);
}

/* Drag handle */
.nd-drag-handle {
  width: 40px; height: 4px;
  background: #e2eaf5;
  border-radius: 4px;
  margin: 0 auto 18px;
}

/* Header row */
.nd-sheet-header {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 14px;
}

.nd-sheet-icon-wrap {
  width: 52px; height: 52px;
  border-radius: 16px;
  display: flex; align-items: center; justify-content: center;
  font-size: 22px;
  flex-shrink: 0;
}

.nd-sheet-meta {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.nd-sheet-tag {
  display: inline-flex;
  align-items: center;
  font-size: 11px;
  font-weight: 700;
  border-radius: 20px;
  padding: 3px 10px;
  width: fit-content;
}

.nd-sheet-time {
  font-size: 11.5px;
  color: #9aadc9;
  font-weight: 500;
}

.nd-close-btn {
  width: 32px; height: 32px;
  border-radius: 50%;
  border: 1.5px solid #e2eaf5;
  background: #f8faff;
  color: #9aadc9;
  font-size: 13px;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer;
  flex-shrink: 0;
  transition: all 0.18s;
}

.nd-close-btn:hover { background: #f0f4fa; color: #1a2b4b; }

/* Title */
.nd-sheet-title {
  font-size: 18px;
  font-weight: 800;
  color: #1a2b4b;
  margin-bottom: 14px;
  line-height: 1.2;
}

/* Divider */
.nd-sheet-divider {
  height: 1px;
  background: #f0f4fa;
  margin-bottom: 14px;
}

/* Detail text */
.nd-sheet-detail {
  font-size: 13px;
  color: #5a6882;
  line-height: 1.7;
  margin-bottom: 22px;
}

/* Action button */
.nd-action-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  background: #2563eb;
  color: #fff;
  border: none;
  border-radius: 14px;
  padding: 14px;
  font-size: 14px;
  font-weight: 700;
  text-decoration: none;
  cursor: pointer;
  box-shadow: 0 4px 16px rgba(37,99,235,0.28);
  transition: all 0.2s;
  margin-bottom: 10px;
}

.nd-action-btn:hover { background: #1d4ed8; transform: translateY(-1px); }

/* Dismiss button */
.nd-dismiss-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  background: none;
  border: 1.5px solid #e2eaf5;
  color: #9aadc9;
  border-radius: 14px;
  padding: 12px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.18s;
}

.nd-dismiss-btn:hover { background: #f8faff; color: #5a6882; }

